// src/pages/Accueil.jsx
import React from 'react';

export default function Accueil({ navigate }) {

  const outils = [
    {
      key: 'orderform',
      label: 'Nouvelle\nFacture',
      icon: (
        <svg width="24" height="24" viewBox="0 0 24 24" fill="none"
          stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
          <rect x="4" y="2" width="12" height="16" rx="1"/>
          <line x1="7" y1="6"  x2="13" y2="6"/>
          <line x1="7" y1="9"  x2="13" y2="9"/>
          <line x1="7" y1="12" x2="10" y2="12"/>
          <circle cx="17" cy="17" r="4"/>
          <line x1="17" y1="15" x2="17" y2="19"/>
          <line x1="15" y1="17" x2="19" y2="17"/>
        </svg>
      ),
    },
    {
      key: 'recherche',
      label: 'Recherche',
      icon: (
        <svg width="24" height="24" viewBox="0 0 24 24" fill="none"
          stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
          <rect x="3" y="4" width="14" height="16" rx="1"/>
          <line x1="6" y1="8"  x2="14" y2="8"/>
          <line x1="6" y1="11" x2="14" y2="11"/>
          <line x1="6" y1="14" x2="10" y2="14"/>
          <circle cx="18" cy="18" r="3"/>
          <line x1="20.5" y1="20.5" x2="22" y2="22"/>
        </svg>
      ),
    },
    {
      key: 'articles',
      label: 'Articles',
      icon: (
        <svg width="24" height="24" viewBox="0 0 24 24" fill="none"
          stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
          <path d="M6 2L3 6v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2V6l-3-4z"/>
          <line x1="3" y1="6" x2="21" y2="6"/>
          <path d="M16 10a4 4 0 0 1-8 0"/>
        </svg>
      ),
    },
    {
      key: 'etats',
      label: 'États',
      icon: (
        <svg width="24" height="24" viewBox="0 0 24 24" fill="none"
          stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
          <path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/>
          <polyline points="14 2 14 8 20 8"/>
          <line x1="8" y1="13" x2="16" y2="13"/>
          <line x1="8" y1="17" x2="16" y2="17"/>
        </svg>
      ),
    },
    {
      key: 'aides',
      label: 'Aide',
      icon: (
        <svg width="24" height="24" viewBox="0 0 24 24" fill="none"
          stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
          <circle cx="12" cy="12" r="10"/>
          <path d="M9.09 9a3 3 0 0 1 5.83 1c0 2-3 3-3 3"/>
          <circle cx="12" cy="17" r="0.5" fill="currentColor"/>
        </svg>
      ),
    },
    {
      key: '__quitter',
      label: 'Quitter',
      icon: (
        <svg width="24" height="24" viewBox="0 0 24 24" fill="none"
          stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
          <path d="M9 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h4"/>
          <polyline points="16 17 21 12 16 7"/>
          <line x1="21" y1="12" x2="9" y2="12"/>
        </svg>
      ),
    },
  ];

  const handleClick = (key) => {
    if (key === '__quitter') {
      if (window.confirm('Quitter GestionMagasin ?')) window.close();
    } else {
      navigate(key);
    }
  };

  /* ── Styles inline ── */
  const win = {
    fontFamily: 'Tahoma, Arial, sans-serif',
    fontSize: 13,
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    minHeight: '100vh',
    background: '#008080',   /* fond bureau Windows */
  };

  const fenetre = {
    background: '#d4d0c8',
    border: '2px solid #888',
    borderTop: '2px solid #fff',
    borderLeft: '2px solid #fff',
    boxShadow: '3px 3px 8px rgba(0,0,0,0.5)',
    minWidth: 460,
  };

  const titleBar = {
    background: 'linear-gradient(to right, #0a246a, #a6b8d8)',
    padding: '3px 6px',
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    userSelect: 'none',
  };

  const menuBar = {
    display: 'flex',
    gap: 0,
    padding: '2px 4px',
    borderBottom: '1px solid #aaa',
    background: '#d4d0c8',
  };

  const menuItem = {
    padding: '2px 8px',
    fontSize: 13,
    cursor: 'default',
    borderRadius: 2,
    background: 'none',
    border: 'none',
    fontFamily: 'inherit',
  };

  const toolbar = {
    display: 'flex',
    gap: 2,
    padding: '4px 6px',
    borderBottom: '1px solid #aaa',
    background: '#d4d0c8',
  };

  const btnTool = (hovered) => ({
    display: 'flex',
    flexDirection: 'column',
    alignItems: 'center',
    justifyContent: 'center',
    gap: 3,
    padding: '4px 6px',
    width: 64,
    minHeight: 56,
    border: hovered ? '1px solid #888' : '1px solid transparent',
    borderTop: hovered ? '1px solid #fff' : '1px solid transparent',
    borderLeft: hovered ? '1px solid #fff' : '1px solid transparent',
    background: hovered ? '#e8e8e8' : 'transparent',
    cursor: 'pointer',
    fontFamily: 'inherit',
    fontSize: 11,
    color: '#000',
    borderRadius: 2,
    textAlign: 'center',
    whiteSpace: 'pre-line',
    lineHeight: 1.2,
  });

  const statusBar = {
    padding: '2px 8px',
    borderTop: '1px solid #aaa',
    background: '#d4d0c8',
    fontSize: 11,
    color: '#444',
    display: 'flex',
    gap: 10,
  };

  const [hovered, setHovered] = React.useState(null);

  return (
    <div style={win}>
      <div style={fenetre}>

        {/* ── Barre de titre ── */}
        <div style={titleBar}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
            <svg width="14" height="14" viewBox="0 0 24 24" fill="white">
              <path d="M3 3h18v2H3V3zm0 4h18v2H3V7zm0 4h18v2H3v-2zm0 4h12v2H3v-2z"/>
            </svg>
            <span style={{ color: '#fff', fontWeight: 700, fontSize: 13 }}>GestionMagasin</span>
          </div>
          <div style={{ display: 'flex', gap: 2 }}>
            <button style={{ width: 16, height: 14, fontSize: 9, background: '#c0c0c0', border: '1px solid #888', cursor: 'pointer', fontFamily: 'inherit' }}>─</button>
            <button style={{ width: 16, height: 14, fontSize: 9, background: '#c0c0c0', border: '1px solid #888', cursor: 'pointer', fontFamily: 'inherit' }}>□</button>
            <button
              onClick={() => { if (window.confirm('Quitter GestionMagasin ?')) window.close(); }}
              style={{ width: 16, height: 14, fontSize: 9, background: '#c0c0c0', border: '1px solid #888', cursor: 'pointer', color: '#900', fontWeight: 700, fontFamily: 'inherit' }}>✕</button>
          </div>
        </div>

        {/* ── Barre de menu ── */}
        <div style={menuBar}>
          {[
            { label: 'Fichier', action: null },
            { label: 'Vue',     action: null },
            { label: 'Aide',    action: () => navigate('aides') },
          ].map(m => (
            <button key={m.label} style={menuItem}
              onMouseEnter={e => e.currentTarget.style.background = '#0a246a' || (e.currentTarget.style.color = '#fff')}
              onMouseLeave={e => { e.currentTarget.style.background = 'none'; e.currentTarget.style.color = '#000'; }}
              onClick={m.action || undefined}>
              {m.label}
            </button>
          ))}
        </div>

        {/* ── Barre d'outils ── */}
        <div style={toolbar}>
          {outils.map((o, i) => (
            <React.Fragment key={o.key}>
              {/* séparateur avant Aide et Quitter */}
              {(o.key === 'aides' || o.key === '__quitter') && (
                <div style={{ width: 1, background: '#aaa', margin: '4px 3px', alignSelf: 'stretch' }} />
              )}
              <button
                style={btnTool(hovered === o.key)}
                onMouseEnter={() => setHovered(o.key)}
                onMouseLeave={() => setHovered(null)}
                onClick={() => handleClick(o.key)}
                title={o.label.replace('\n', ' ')}
              >
                {o.icon}
                <span>{o.label}</span>
              </button>
            </React.Fragment>
          ))}
        </div>

        {/* ── Barre de statut ── */}
        <div style={statusBar}>
          <span>Prêt</span>
          <span style={{ marginLeft: 'auto' }}>GestionMagasin v1.0</span>
        </div>

      </div>
    </div>
  );
}
